### Server Lifecycle Test (server_lifecycle.rs)

```rust
// tests/e2e/server_lifecycle.rs

use super::helpers::*;

#[test]
fn test_server_startup_shows_banner() {
    let runner = TestServerRunner::new(E2ETestConfig::human_mode());
    let result = runner.run_server(&["--demo-mode"]);

    result.print_diagnostics();

    // Should show banner on stderr
    assert!(result.stderr_contains("FastMCP"), "Should show server name in banner");

    // stdout should be clean (no rich output)
    assert!(result.stdout_is_valid_jsonrpc(), "stdout must be valid JSON-RPC only");
}

#[test]
fn test_server_shows_capabilities() {
    let runner = TestServerRunner::new(E2ETestConfig::human_mode());
    let result = runner.run_server(&["--show-capabilities"]);

    result.print_diagnostics();

    // Should show registered tools/resources/prompts
    assert!(result.stderr_contains("Tools") || result.stderr_contains("tools"));
}

#[test]
fn test_server_handles_request_and_logs() {
    let runner = TestServerRunner::new(E2ETestConfig::human_mode());

    let messages = &[
        r#"{"jsonrpc":"2.0","id":1,"method":"initialize","params":{}}"#,
        r#"{"jsonrpc":"2.0","id":2,"method":"tools/list","params":{}}"#,
    ];

    let result = runner.run_with_messages(messages);
    result.print_diagnostics();

    // stdout should have JSON-RPC responses
    assert!(result.stdout_contains("result"));

    // stderr should have log output
    assert!(result.stderr_contains("initialize") || result.stderr_contains("tools/list"));
}

#[test]
fn test_server_graceful_shutdown() {
