+pub struct TestTraceBuilder {
+    name: String,
+    metadata: HashMap<String, serde_json::Value>,
+    console_output: bool,
+    min_level: TraceLevel,
+}
+
+impl TestTraceBuilder {
+    /// Creates a new trace builder.
+    pub fn new(name: impl Into<String>) -> Self {
